Implementation sketch:
```rust
pub struct LearningWriter<'a> {
    db_dir: Option<&'a Path>,
    pending: Vec<PendingEmbed>,
}
struct PendingEmbed { learning_id: i64, title: String, content: String }

impl<'a> LearningWriter<'a> {
    pub fn new(db_dir: Option<&'a Path>) -> Self { Self { db_dir, pending: Vec::new() } }
    pub fn record(&mut self, conn: &Connection, params: RecordLearningParams) -> TaskMgrResult<RecordLearningResult> {
        let title = params.title.clone();
        let content = params.content.clone();
        let result = record_learning(conn, params)?;
        if self.db_dir.is_some() {
            self.pending.push(PendingEmbed { learning_id: result.learning_id, title, content });
        }
        Ok(result)
    }
    pub fn flush(mut self, conn: &Connection) -> usize {
        let Some(dir) = self.db_dir else { return 0; };
        if self.pending.is_empty() { return 0; }
        let items: Vec<(i64, String, String)> = std::mem::take(&mut self.pending)
            .into_iter().map(|p| (p.learning_id, p.title, p.content)).collect();
        try_embed_learnings_batch(conn, dir, &items)
    }
}
impl Drop for LearningWriter<'_> {
    fn drop(&mut self) {
        if !self.pending.is_empty() {
            eprintln!("Warning: LearningWriter dropped with {} un-flushed pending embedding(s). Call .flush() before dropping.", self.pending.len());
        }
    }
}
```

